1	/**
2	 * Entire CLI detection and checkpoint resolution.
3	 *
4	 * Gateway utilities — Cairn never parses Entire's internal formats directly.
5	 * All data flows through `entire explain` or `entire sessions info`.
6	 */
7	
8	/**
9	 * Check if `entire` CLI is on PATH.
10	 */
11	export async function isEntireOnPath(): Promise<boolean> {
12	  return !!Bun.which("entire");
13	}
14	
15	/**
16	 * Check if Entire is enabled in the given project directory.
17	 * Runs `entire status` and checks for the "Enabled" indicator in stdout.
18	 * `entire status` always exits 0 regardless of state, so we parse the output.
19	 */
20	export async function isEntireEnabled(cwd: string): Promise<boolean> {
21	  if (!(await isEntireOnPath())) return false;
22	
23	  try {
24	    const proc = Bun.spawn(["entire", "status"], {
25	      cwd,
26	      stdout: "pipe",
27	      stderr: "ignore",
28	    });
29	    const output = await new Response(proc.stdout).text();
30	    const exitCode = await proc.exited;
31	    if (exitCode !== 0) return false;
32	
33	    return output.includes("Enabled");
34	  } catch {
35	    return false;
36	  }
37	}
38	
39	/**
40	 * Get checkpoint ID from the most recent commit message in the given cwd.
41	 * Reads the `Entire-Checkpoint:` trailer from HEAD.
42	 * Returns null if no checkpoint trailer found.
43	 */
44	export async function getHeadCheckpointId(cwd: string): Promise<string | null> {
45	  try {
46	    const proc = Bun.spawn(
47	      ["git", "log", "-1", "--format=%B", "HEAD"],
48	      { cwd, stdout: "pipe", stderr: "ignore" }
49	    );
50	    const output = await new Response(proc.stdout).text();
51	    const exitCode = await proc.exited;
52	    if (exitCode !== 0) return null;
53	
54	    const match = output.match(/Entire-Checkpoint:\s*([a-f0-9]+)/i);
55	    return match?.[1] ?? null;
56	  } catch {
57	    return null;
58	  }
59	}
60	
61	/**
62	 * Run `entire explain --checkpoint <id> --short` and return the output.
63	 * Returns null on failure.
64	 */
65	export async function explainCheckpoint(
66	  checkpointId: string,
67	  cwd: string
68	): Promise<string | null> {
69	  try {
70	    const proc = Bun.spawn(
71	      ["entire", "explain", "--checkpoint", checkpointId, "--short", "--no-pager"],
72	      { cwd, stdout: "pipe", stderr: "ignore" }
73	    );
74	    const output = await new Response(proc.stdout).text();
75	    const exitCode = await proc.exited;
76	    return exitCode === 0 ? output.trim() : null;
77	  } catch {
78	    return null;
79	  }
80	}
81	
82	/**
83	 * Run `entire explain --checkpoint <id>` (default detail) and return the output.
84	 * Returns null on failure.
85	 */
86	export async function explainCheckpointFull(
87	  checkpointId: string,
88	  cwd: string
89	): Promise<string | null> {
90	  try {
91	    const proc = Bun.spawn(
92	      ["entire", "explain", "--checkpoint", checkpointId, "--no-pager"],
93	      { cwd, stdout: "pipe", stderr: "ignore" }
94	    );
95	    const output = await new Response(proc.stdout).text();
96	    const exitCode = await proc.exited;
97	    return exitCode === 0 ? output.trim() : null;
98	  } catch {
99	    return null;
100	  }
101	}
102

